Code.Terraform:
```hcl
# レプリケーションセットが存在し、ACTIVE になることを確認する
resource "aws_ssmincidents_replication_set" "example" {
  regions {                      # 重要: レプリケーションセットを作成してACTIVEにできるようにする
    region_name = "us-east-1"
  }
}

# 最小限の応答計画を作成する
resource "aws_ssmincidents_response_plan" "example" {
  name = "<example_resource_name>"  # 重要：少なくとも1つのレスポンスプランが存在することを保証します

  incident_template {                # 重大: 必須 template for the plan
    title  = "<example_title>"
    impact = 5
  }
}
```
